fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    if (n == 0) return 0L

    // dp_up[i]: maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is greater than the previous element (i.e., ..., < nums[i])
    val dpUp = LongArray(n) { nums[it] }

    // dp_down[i]: maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is smaller than the previous element (i.e., ..., > nums[i])
    val dpDown = LongArray(n) { nums[it] }

    var maxScore = nums[0]

    for (i in 1 until n) {
        // Base case: length 1 subsequence ending at i
        dpUp[i] = nums[i]
        dpDown[i] = nums[i]

        for (j in 0 until i) {
            // Check the distance condition: i - j >= k
            if (i - j >= k) {
                val prevVal = nums[j]
                val currVal = nums[i]

                // 1. Calculate dpUp[i] (ends with < nums[i])
                // The previous element nums[j] must be smaller than nums[i] (currVal > prevVal)
                // and the subsequence ending at j must have ended with nums[j] being smaller than its predecessor (..., > nums[j])
                if (currVal > prevVal) {
                    // Extend a sequence ending at j that was "down"
                    dpUp[i] = maxOf(dpUp[i], dpDown[j] + currVal)
                }

                // 2. Calculate dpDown[i] (ends with > nums[i])
                // The previous element nums[j] must be larger than nums[i] (currVal < prevVal)
                // and the subsequence ending at j must have ended with nums[j] being larger than its predecessor (..., < nums[j])
                if (currVal < prevVal) {
                    // Extend a sequence ending at j that was "up"
                    dpDown[i] = maxOf(dpDown[i], dpUp[j] + currVal)
                }
            }
        }
        // Update overall maximum score
        maxScore = maxOf(maxScore, dpUp[i].coerceAtLeast(dpDown[i]))
    }

    return maxScore
