fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    if (n == 0) return 0L

    // dp[i][0]: maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is expected to be the "smaller" element (i.e., the last transition was >)
    // e.g., ... > nums[i]
    // dp[i][1]: maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is expected to be the "larger" element (i.e., the last transition was <)
    // e.g., ... < nums[i]
    val dp = Array(n) { LongArray(2) { 0L } }
    var maxScore = 0L

    for (i in 0 until n) {
        // Base case: A subsequence of length 1 always exists, score is nums[i]
        dp[i][0] = nums[i]
        dp[i][1] = nums[i]

        for (j in 0 until i) {
            if (i - j >= k) {
                // Transition to dp[i][0] (ending with ... > nums[i]):
                // The previous element nums[j] must have been the larger one,
                // so we transition from dp[j][1] (ending with ... < nums[j]).
                // We need nums[j] > nums[i] for ... > nums[i] to be valid.
                if (nums[j] > nums[i]) {
                    dp[i][0] = maxOf(dp[i][0], dp[j][1] + nums[i])
